    def _invokeex_(self, dispid, lcid, wFlags, args, kwargs, serviceProvider):
        '''A stub for _invokeex_ - should never be called.

        Simply raises an exception.
        '''
        raise error('This class does not provide _invokeex_ semantics')

    
